#include<math.h>
int main(void){
int n,i,q=0,max=-1,q1;
scanf("%d",&n);
int a[5];
a[0]=100;
a[1]=20;
a[2]=10;
a[3]=5;
a[4]=1;
while(n>0){
  for(i=4;i>=0;i--){

     if(a[i]<=n){
   max=a[i];
    }
  }
  q1=n/max;
  q=q+q1;
  n=n-(q1*max);
}
printf("%d",q);
  return 0;
}

