use std::io::{self, stdin};

fn main() -> io::Result<()> {
    let mut buffer = String::new();
    let input = stdin();
    input.read_line(&mut buffer)?;
    let mut money: u32 = buffer.trim().parse().expect("Not int");
    let mut bills = 0;
    let denoms = [100, 20, 10, 5, 1];
    for denom in &denoms {
        bills += money / denom;
        money %= denom;
    }
    println!("{}", bills);
    Ok(())
}
